class Solution:
    def maxVowels(self, s: str, k: int) -> int:
        vowels = set('aeiou')
        best = cur = sum(1 for c in s[:k] if c in vowels)
        for i in range(k, len(s)):
            cur += (s[i] in vowels) - (s[i - k] in vowels)
            if cur > best:
                best = cur
        return best

