var maxVowels = function(s, k) {
    const vowels = new Set(['a','e','i','o','u']);
    let cur = 0;
    for (let i = 0; i < k; i++) if (vowels.has(s[i])) cur++;
    let best = cur;
    for (let i = k; i < s.length; i++) {
        cur += (vowels.has(s[i]) ? 1 : 0) - (vowels.has(s[i - k]) ? 1 : 0);
        if (cur > best) best = cur;
    }
    return best;
};
